import random, math, numpy as np

def good_measure(L, xs, ws):
    # f(t)=sum ws_i 1_{t in [x_i-1,x_i] mod L}; compute measure f>=1
    events=[]
    for x,w in zip(xs,ws):
        start=(x-1)%L; end=x%L
        if start<=end:
            events.append((start,w)); events.append((end,-w))
        else:
            events.append((0,w)); events.append((end,-w)); events.append((start,w)); events.append((L,-w))
    events.sort()
    val=0.0; last=0.0; meas=0.0
    # handle events at 0
    i=0
    while i<len(events) and abs(events[i][0]-0)<1e-12:
        val += events[i][1]; i+=1
    last=0.0
    while i<len(events):
        t=events[i][0]
        if t>last and val>=1-1e-12:
            meas += t-last
        while i<len(events) and abs(events[i][0]-t)<1e-12:
            val += events[i][1]; i+=1
        last=t
    if L>last and val>=1-1e-12:
        meas += L-last
    return meas

