def tail_prob(weights,q):
    n=len(weights); prob=0
    for mask in range(1<<n):
        s=sum(weights[i] for i in range(n) if mask>>i&1)
        k=mask.bit_count()
        if s>q+1e-12:
            prob += q**k*(1-q)**(n-k)
    return prob
